use std::collections::HashMap;

struct Record {
    id: u32,
    status_code: u16,
    expected_count: u32,
}

fn process_batch(records: Vec<Record>) -> HashMap<u32, String> {
    let mut results = HashMap::new();
    for record in records {
        if record.status_code == 200 && record.expected_count > 0 {
            results.insert(record.id, format!( "Success: Expected {} entries processed.", record.expected_count));
        } else {
            results.insert(record.id, String::from("Failure: Status or count mismatch."));
        }
    }
    results
}

use std::collections::HashMap;
use std::hash::{Hash, Hasher};

struct ConfigKey(u32);

impl PartialEq for ConfigKey {
    fn eq(&self, other: &Self) -> bool {
        *self == *other
    }
}

impl Eq for ConfigKey {}

impl Hash for ConfigKey {
    fn hash<H: Hasher>(&self, state: &mut H) {
        self.0.hash(state);
    }
}

type KnownSetting = u32;

struct TypeSafeConfigStore {
    settings: HashMap<ConfigKey, KnownSetting>,
}

impl TypeSafeConfigStore {
    fn new() -> Self {
        TypeSafeConfigStore { settings: HashMap::new() }
    }

    fn add_setting(&mut self, key: ConfigKey, value: KnownSetting) {
        self.settings.insert(key, value);
    }

    fn get_setting(&self, key: &ConfigKey) -> Option<KnownSetting> {
        self.settings.get(key).cloned()
    }
}

fn main() {
    let mut store = TypeSafeConfigStore::new();
    store.add_setting(ConfigKey(10), 42);
    store.add_setting(ConfigKey(50), 99);

    let key_to_find = ConfigKey(10);
    match store.get_setting(&key_to_find) {
        Some(val) => println!("Found setting: {}", val),
        None => {}
    }

    let wrong_key = ConfigKey(1);
    match store.get_setting(&wrong_key) {
        Some(_) => {}
        None => println!("Correctly reported missing setting for key 1.")
    }
}

use std::collections::HashMap;
use std::hash::{Hash, Hasher};

struct ChunkId {
    size: u32,
}
impl PartialEq for ChunkId {
    fn eq(&self, other: &Self) -> bool {
        self.size == other.size
    }
}
impl Eq for ChunkId {}
impl Hash for ChunkId {
    fn hash<H: Hasher> (&self, state: &mut H) {
        state.write_u32(self.size)
    }
}

fn deduplicate_chunks(chunk_sizes: &[u32]) -> HashMap<ChunkId, u32> {
    let mut seen_hashes = HashMap::new();

    for &size in chunk_sizes { 
        let id = ChunkId { size };
        if !seen_hashes.contains_key(&id) {
            seen_hashes.insert(id, 1);
        } else {
            *seen_hashes.get_mut(&id).unwrap() += 1;
        }
    }
    seen_hashes
}

use std::collections::HashMap;
use std::io::{self};

struct ConfigManager {
    mappings: HashMap<String, Vec<i32>>
}

impl ConfigManager {
    fn new() -> Self {
        ConfigManager { mappings: HashMap::new() }
    }

    fn add_mapping(&mut self, group_name: &str, source_ids: &[i32], dest_count: i32) -> Result<(), &'static str> {
        if source_ids.len() as i32 != dest_count {
            return Err("The number of provided source IDs must exactly match the required destination count.");
        }
        let key = group_name.to_string();
        self.mappings.insert(key, source_ids.to_vec());
        Ok(())
    }

    fn print_status(&self) -> Result<(), io::Error> {
        println!("--- Config Manager Status ---");
        for (group, sources) in &self.mappings {
            println!("Group: {}", group);
            println!("  Source IDs stored count: {}", sources.len());
        }
        Ok(()) 
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut manager = ConfigManager::new();

    manager.add_mapping("dotfile_group_a", &[10, 20], 2)?;

    match manager.add_mapping("dotfile_group_b", &[30], 1) {
        Ok(_) => {},
        Err(e) => println!("Error setting up group B: {}", e),
    }

    if let Err(e) = manager.add_mapping("fail_test", &[5], 2) {
        println!("Successfully caught expected error for fail_test: {}", e);
    }

    manager.print_status()?;
    Ok(())
}

use std::collections::HashMap;
use serde::{Deserialize, Serialize};

#[derive(Debug, Clone, PartialEq, Eq, Hash, Deserialize, Serialize)]
struct SchemaField {
    name: String,
    data_type: String,
}

#[derive(Debug, Deserialize, Serialize)]
struct ObjectSchema {
    fields: HashMap<String, SchemaField>,
}

fn validate_instance(schema: &ObjectSchema, instance_map: &HashMap<String, serde_json::Value>) -> bool {
    if schema.fields.len() != instance_map.len() {
        return false;
    }

    for (field_name, field_def) in &schema.fields {
        match instance_map.get(field_name) {
            Some(value) => {
                let expected_type = &field_def.data_type;
                if !check_type(&value, expected_type) {
                    return false;
                }
            }
            None => return false,
        }
    }
    true
}

fn check_type(value: &serde_json::Value, expected_type: &str) -> bool {
    match expected_type.to_lowercase().as_str() {
        "string" => match value { 
            serde_json::Value::String(_) => true,
            _ => false,
        },
        "integer" | "number" => match value { 
            serde_json::Value::Number(_) => true,
            _ => false,
        },
        "boolean" => match value { 
            serde_json::Value::Bool(_) => true,
            _ => false,
        },
        _ => false,
    }
}

fn main() {
    let schema = ObjectSchema {
        fields: [
            ("user_id".to_string(), SchemaField { name: "user_id".to_string(), data_type: "integer".to_string() }),
            ("username".to_string(), SchemaField { name: "username".to_string(), data_type: "string".to_string() }),
            ("is_active".to_string(), SchemaField { name: "is_active".to_string(), data_type: "boolean".to_string() }),
        ].iter().cloned().collect(),
    };

    let mut instance: HashMap<String, serde_json::Value> = HashMap::new();
    instance.insert("user_id".to_string(), serde_json::json!(1024));
    instance.insert("username".to_string(), serde_json::json!("dev_user"));
    instance.insert("is_active".to_string(), serde_json::json!(true));

    let is_valid = validate_instance(&schema, &instance);
    println!("Schema validation result: {}", if is_valid { "Success" } else { "Failure" });
}
